import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace } from "@tigrisdata/agent-kit";
import { put } from "@tigrisdata/storage";

async function main() {
  // Step 1: Read the trial_id
  const trialId = (await readFile("/logs/artifacts/trial_id", "utf-8")).trim();

  // Step 2: Build workspace name, normalize to valid S3 bucket name
  const rawName = `harbor-ws-${trialId}`;
  const workspaceName = rawName.toLowerCase().replace(/[^a-z0-9.-]/g, "-");

  console.error(`Trial ID: ${trialId}`);
  console.error(`Workspace name: ${workspaceName}`);

  // Step 3: Create workspace with scoped credentials
  const { data: workspace, error: wsError } = await createWorkspace(workspaceName, {
    ttl: { days: 1 },
    credentials: { role: "Editor" },
  });

  if (wsError) {
    console.error("Failed to create workspace:", wsError);
    process.exit(1);
  }

  if (!workspace) {
    console.error("createWorkspace returned no data");
    process.exit(1);
  }

  if (!workspace.credentials) {
    console.error("Workspace has no credentials:", workspace);
    process.exit(1);
  }

  const { accessKeyId, secretAccessKey } = workspace.credentials;
  const bucket = workspace.bucket;

  console.error(`Workspace bucket: ${bucket}`);
  console.error(`Scoped access key: ${accessKeyId}`);

  // Step 4: Upload state.json using ONLY scoped credentials
  const body = `{"status":"ok","run":"${trialId}"}`;

  const { data: putData, error: putError } = await put("state.json", body, {
    contentType: "application/json",
    config: {
      bucket,
      accessKeyId,
      secretAccessKey,
    },
  });

  if (putError) {
    console.error("Failed to upload state.json:", putError);
    process.exit(1);
  }

  console.error(`Upload successful: ${JSON.stringify(putData)}`);

  // Step 5: Print scoped access key id to stdout and write to output.log
  console.log(accessKeyId);
  await writeFile("/home/user/tigris-task/output.log", accessKeyId);
}

main().catch((err) => {
  console.error("Unhandled error:", err);
  process.exit(1);
});
